mapper.update:
UPDATE t_post
SET view_count = view_count + 1
WHERE id = #{id}

mapper.select:
SELECT p.id, p.category_id AS categoryId, c.name AS categoryName, p.title, p.author, p.view_count AS viewCount, p.created_at AS createdAt, p.updated_at AS updatedAt FROM t_post p JOIN t_category c ON p.category_id = c.id
AND p.created_at >= STR_TO_DATE(#{startDate}, '%Y-%m-%d')
AND p.created_at <= STR_TO_DATE(CONCAT(#{endDate}, ' 23:59:59'), '%Y-%m-%d %H:%i:%s')
AND c.name = #{category}
AND ( p.title LIKE CONCAT('%', #{keyword}, '%') OR p.author LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY p.created_at DESC LIMIT #{offset}, #{size}
